Ok, so it turns out the whole `kind()` and `itemsize()` stuff is actually not necessary and it's possible to just do:

```
const auto pyarray_dtype = reinterpret_borrow<pybind11::dtype>(detail::array_proxy(src.ptr())->descr);
if (pyarray_dtype == pybind11::dtype::of<float>()) {
	// float (float32) type
} else if (pyarray_dtype == pybind11::dtype::of<double>()) {
	// double-type (float64)
}
```
